368→  const fileToBase64 = async (file: File) => {
369→    const readAsDataUrl = (target: Blob) =>
370→      new Promise<string>((resolve, reject) => {
371→        const reader = new FileReader();
372→        reader.onload = () => {
373→          if (typeof reader.result === 'string') {
374→            resolve(reader.result);
375→            return;
376→          }
377→          reject(new Error('Unable to read file.'));
378→        };
379→        reader.onerror = () => reject(new Error('Unable to read file.'));
380→        reader.readAsDataURL(target);
381→      });
382→
383→    if (!file.type.startsWith('image/')) {
384→      return await readAsDataUrl(file);
385→    }
386→
387→    // Keep original capture when possible so EXIF (GPS/time/device) reaches server-side forensics.
388→    if (file.size <= MAX_SUBMISSION_IMAGE_BYTES) {
389→      return await readAsDataUrl(file);
390→    }
391→
392→    const loadImage = (objectUrl: string) =>
393→      new Promise<HTMLImageElement>((resolve, reject) => {
394→        const img = new Image();
395→        img.onload = () => resolve(img);
396→        img.onerror = () => reject(new Error('Unable to decode image.'));
397→        img.src = objectUrl;
398→      });
399→
400→    const objectUrl = URL.createObjectURL(file);
401→    try {
402→      const img = await loadImage(objectUrl);
403→      const maxDimension = Math.max(img.width, img.height);
404→      const scale = maxDimension > MAX_UPLOAD_DIMENSION ? MAX_UPLOAD_DIMENSION / maxDimension : 1;
405→      const width = Math.max(1, Math.round(img.width * scale));
406→      const height = Math.max(1, Math.round(img.height * scale));
407→      const canvas = document.createElement('canvas');
408→      canvas.width = width;
409→      canvas.height = height;
410→      const ctx = canvas.getContext('2d');
411→      if (!ctx) {
412→        return await readAsDataUrl(file);
413→      }
414→      ctx.drawImage(img, 0, 0, width, height);
415→      const quality = isLowEndDevice ? IMAGE_QUALITY_LOW_END : IMAGE_QUALITY_DEFAULT;
416→      const compressed = canvas.toDataURL('image/jpeg', quality);
417→      return await preserveJpegExif(file, compressed);
418→    } catch {
419→      return await readAsDataUrl(file);
420→    } finally {
421→      URL.revokeObjectURL(objectUrl);
422→    }
423→  };
